bd list --type=agent --desc-contains="role_type: witness" --json | python3 -c "
import json, sys, re
data = json.load(sys.stdin)
matches = [b for b in data if b.get('status') != 'closed' and re.search(r'(?m)^\s*rig: lesson_factory\s*$', b.get('description', ''))]
if len(matches) == 1:
    print(matches[0]['id'])
elif len(matches) == 0:
    print('ERROR: No witness agent bead found for lesson_factory', file=sys.stderr)
else:
    print('ERROR: Multiple matches', file=sys.stderr)
    for m in matches:
        print(f'  {m[\"id\"]}', file=sys.stderr)
"
